
import React from 'react';
import type { Course } from '../types/contentful';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import CardActions from '@mui/material/CardActions';
import Button from '@mui/material/Button';
import Typography from '@mui/material/Typography';
import Link from 'next/link';

interface CourseCardProps {
    course: Course;
}

const CourseCard: React.FC<CourseCardProps> = ({ course }) => {
    const title = course.fields?.pageTitle ?? 'Untitled course';
    const introduction = course.fields?.introduction ?? '';
    const slug = course.fields?.slug ?? course.sys.id;

    return (
        <Card
            sx={{
                maxWidth: 600,
                width: '100%',
                boxShadow: 3,
                '&:hover': {
                    boxShadow: 6,
                    transform: 'translateY(-4px)',
                    transition: 'all 0.3s ease'
                },
                transition: 'all 0.3s ease'
            }}
        >
            <CardContent>
                <Typography variant="h5" component="h2" gutterBottom sx={{ fontWeight: 600 }}>
                    {title}
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    {introduction}
                </Typography>
            </CardContent>
            <CardActions>
                <Link href={`/courses/${slug}`} passHref style={{ textDecoration: 'none' }}>
                    <Button size="medium" variant="contained" color="primary">
                        View Details
                    </Button>
                </Link>
            </CardActions>
        </Card>
    );
};

export default CourseCard;